#include <stdio.h>

int main() {
    int n; scanf("%d", &n);
    int a[100001];
    for (int i = 0; i < n; i++) scanf("%d", &a[i]);
    int max_s = a[0], cur = a[0];
    for (int i = 1; i < n; i++) {
        cur = a[i] > cur + a[i] ? a[i] : cur + a[i];
        if (cur > max_s) max_s = cur;
    }
    printf("%d\n", max_s);
    return 0;
}

let () =
  let n = Scanf.scanf " %d" Fun.id in
  let a = Array.init n (fun _ -> Scanf.scanf " %d" Fun.id) in
  let max_s = ref a.(0) and cur = ref a.(0) in
  for i = 1 to n-1 do
    cur := max a.(i) (!cur + a.(i));
    if !cur > !max_s then max_s := !cur
  done;
